  struct
    type nonrec t =
      {
      waveID: WaveID.t option [@ocaml.doc "Wave ID."];
      arn: ARN.t option [@ocaml.doc "Wave ARN."];
      name: WaveName.t option [@ocaml.doc "Wave name."];
      description: WaveDescription.t option [@ocaml.doc "Wave description."];
      isArchived: Boolean.t option [@ocaml.doc "Wave archival status."];
      waveAggregatedStatus: WaveAggregatedStatus.t option
        [@ocaml.doc "Wave aggregated status."];
