        [@ocaml.doc "Wave creation dateTime."];
      lastModifiedDateTime: ISO8601DatetimeString.t option
        [@ocaml.doc "Wave last modified dateTime."];
      tags: TagsMap.t option [@ocaml.doc "Wave tags."]}
    type nonrec error =
      [ `ConflictException of ConflictException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ServiceQuotaExceededException of ServiceQuotaExceededException.t 
      | `UninitializedAccountException of UninitializedAccountException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?waveID =
      fun ?arn ->
        fun ?name ->
          fun ?description ->
            fun ?isArchived ->
              fun ?waveAggregatedStatus ->
                fun ?creationDateTime ->
                  fun ?lastModifiedDateTime ->
                    fun ?tags ->
                      fun () ->
                        {
                          waveID;
                          arn;
                          name;
                          description;
                          isArchived;
                          waveAggregatedStatus;
                          creationDateTime;
                          lastModifiedDateTime;
                          tags
                        }
    let error_of_json name json =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ServiceQuotaExceededException" ->
          `ServiceQuotaExceededException
            (ServiceQuotaExceededException.of_json json)
      | "UninitializedAccountException" ->
          `UninitializedAccountException
            (UninitializedAccountException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ServiceQuotaExceededException" ->
          `ServiceQuotaExceededException
            (ServiceQuotaExceededException.of_xml xml)
      | "UninitializedAccountException" ->
          `UninitializedAccountException
            (UninitializedAccountException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ConflictException e ->
          `Assoc
            [("error", (`String "ConflictException"));
            ("details", (ConflictException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ServiceQuotaExceededException e ->
          `Assoc
            [("error", (`String "ServiceQuotaExceededException"));
            ("details", (ServiceQuotaExceededException.to_json e))]
      | `UninitializedAccountException e ->
          `Assoc
            [("error", (`String "UninitializedAccountException"));
            ("details", (UninitializedAccountException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("waveID", (Option.map x.waveID ~f:WaveID.to_value));
        ("arn", (Option.map x.arn ~f:ARN.to_value));
