        ("lastModifiedDateTime",
          (Option.map x.lastModifiedDateTime
             ~f:ISO8601DatetimeString.to_value));
        ("tags", (Option.map x.tags ~f:TagsMap.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let tags = (Option.map ~f:TagsMap.of_xml) (Xml.child xml_arg0 "tags") in
      let lastModifiedDateTime =
        (Option.map ~f:ISO8601DatetimeString.of_xml)
          (Xml.child xml_arg0 "lastModifiedDateTime") in
      let creationDateTime =
        (Option.map ~f:ISO8601DatetimeString.of_xml)
          (Xml.child xml_arg0 "creationDateTime") in
      let waveAggregatedStatus =
        (Option.map ~f:WaveAggregatedStatus.of_xml)
          (Xml.child xml_arg0 "waveAggregatedStatus") in
      let isArchived =
        (Option.map ~f:Boolean.of_xml) (Xml.child xml_arg0 "isArchived") in
      let description =
        (Option.map ~f:WaveDescription.of_xml)
          (Xml.child xml_arg0 "description") in
      let name = (Option.map ~f:WaveName.of_xml) (Xml.child xml_arg0 "name") in
      let arn = (Option.map ~f:ARN.of_xml) (Xml.child xml_arg0 "arn") in
      let waveID =
        (Option.map ~f:WaveID.of_xml) (Xml.child xml_arg0 "waveID") in
      make ?tags ?lastModifiedDateTime ?creationDateTime
